const text = query || "male 70kg 175cm 21 years old muscle gain moderate activity";

const lower = text.toLowerCase();

let weightKg = 70;
let heightCm = 175;
let age = 21;
let sex = "male";
let goal = "maintain";
let activity = 1.55;

// extract values
const weightMatch = lower.match(/(\d+)\s*kg/);
if (weightMatch) weightKg = parseInt(weightMatch[1]);

const heightMatch = lower.match(/(\d+)\s*cm/);
if (heightMatch) heightCm = parseInt(heightMatch[1]);

const ageMatch = lower.match(/(\d+)\s*(years|yo)/);
if (ageMatch) age = parseInt(ageMatch[1]);

if (lower.includes("female")) sex = "female";
if (lower.includes("male")) sex = "male";

if (lower.includes("muscle") || lower.includes("bulk")) goal = "muscle gain";
if (lower.includes("fat") || lower.includes("cut")) goal = "fat loss";

if (lower.includes("sedentary")) activity = 1.2;
if (lower.includes("light")) activity = 1.375;
if (lower.includes("moderate")) activity = 1.55;
if (lower.includes("active")) activity = 1.725;
if (lower.includes("very active")) activity = 1.9;

// BMR
let bmr;
if (sex === "male") {
  bmr = 10 * weightKg + 6.25 * heightCm - 5 * age + 5;
} else {
  bmr = 10 * weightKg + 6.25 * heightCm - 5 * age - 161;
}

// calories
let calories = Math.round(bmr * activity);

if (goal === "muscle gain") calories += 250;
if (goal === "fat loss") calories -= 400;

// protein
const proteinMin = Math.round(weightKg * 1.6);
const proteinMax = Math.round(weightKg * 2.2);

return `Nutrition Plan

Input:
${text}

Calories: ${calories} kcal/day
Protein: ${proteinMin}–${proteinMax} g/day

Goal: ${goal}
Activity level: ${activity}

Tip:
- Adjust calories every 2–3 weeks based on progress`;
